<script setup lang="ts">
import {computed, onBeforeUnmount, ref} from "vue";

type Platform = "linux" | "windows" | "docker";

const active = ref<Platform>("linux");

const installCommands: Record<Platform, string> = {
  linux:
    "curl -fsSL https://raw.githubusercontent.com/joao-zanutto/easydocker/main/install/install.sh | sh",
  windows:
    "irm https://raw.githubusercontent.com/joao-zanutto/easydocker/main/install/install.ps1 | iex",
  docker:
    "docker run --rm -it -v /var/run/docker.sock:/var/run/docker.sock:ro joaozanutto2/easydocker:latest",
};

const copyState = ref<"idle" | "copied" | "error">("idle");
let copyResetTimer: ReturnType<typeof setTimeout> | null = null;

const copyLabel = computed(() => {
  if (copyState.value === "copied") return "Copied";
  if (copyState.value === "error") return "Try again";
  return "Copy";
});

const copyButtonTitle = computed(() => {
  if (copyState.value === "copied") return "Command copied to clipboard";
  if (copyState.value === "error") return "Clipboard unavailable, try again";
  return "Copy install command";
});

function setCopyState(state: "idle" | "copied" | "error"): void {
  copyState.value = state;

  if (copyResetTimer) {
    clearTimeout(copyResetTimer);
  }

  if (state !== "idle") {
    copyResetTimer = setTimeout(() => {
      copyState.value = "idle";
    }, 1800);
  }
}

async function copyCurrentCommand(): Promise<void> {
  const command = installCommands[active.value];

  try {
    if (typeof navigator !== "undefined" && navigator.clipboard?.writeText) {
      await navigator.clipboard.writeText(command);
      setCopyState("copied");
      return;
    }

    if (typeof document === "undefined") {
      throw new Error("Clipboard API unavailable");
    }

    const textArea = document.createElement("textarea");
    textArea.value = command;
    textArea.setAttribute("readonly", "");
    textArea.style.position = "absolute";
    textArea.style.left = "-9999px";
    document.body.appendChild(textArea);
    textArea.select();
    const didCopy = document.execCommand("copy");
    document.body.removeChild(textArea);

    if (!didCopy) {
      throw new Error("Copy command failed");
    }

    setCopyState("copied");
  } catch {
    setCopyState("error");
  }
}

onBeforeUnmount(() => {
  if (copyResetTimer) {
    clearTimeout(copyResetTimer);
  }
});
</script>

